async function execute(browser, params) {
    const result = await browser.extractComponent(
        {
            typeName: 'ProductTile',
            schema: '{ name: string; price?: string; detailsLinkSelector: string; }'
        },
        params.productName || ('result number ' + params.position)
    );
    if (!result || !result.detailsLinkSelector) {
        throw new Error('Could not find search result at position ' + params.position);
    }
    await browser.click(result.detailsLinkSelector);
    await browser.awaitPageLoad();
    return { success: true, message: 'Selected: ' + (result.name || 'result ' + params.position) };
}
